args.sparql:
SELECT ?occupation ?occupationLabel (COUNT(?occupation) AS ?count)
WHERE {
  ?person p:P166 [
    ps:P166 wd:Q16447;
    pq:P585 ?awardDate
  ].
  FILTER (YEAR(?awardDate) >= 2004)

  ?person (wdt:P22|wdt:P25) ?parent.

  ?parent wdt:P106 ?occupation.

  OPTIONAL { ?occupation rdfs:label ?occupationLabel. FILTER (lang(?occupationLabel) = "en") }
}
GROUP BY ?occupation ?occupationLabel
ORDER BY DESC(?count)
LIMIT 5
